  /** Sync lại toàn bộ dữ liệu từ price setting sang rate calendar (chỉ những pricesetting active) */
  async syncAllRateCalendar(hotelId: number) {
    const whereCondition = { hotel: { id: hotelId }, isActive: true };

    const priceSettings = await this.repo.find({
      where: whereCondition,
      relations: ['hotel', 'room', 'season'],
    });

    if (!priceSettings.length) {
      return {
        success: true,
        message: 'No active price settings found to sync',
        total: 0,
        synced: 0,
      };
    }

    // Xóa toàn bộ rate calendar liên quan trước
    await this.rateCalendarRepo.deleteMany({
      hotelId: hotelId,
    });

    let syncedCount = 0;
    const errors: Array<{ id: number; error: string }> = [];

    // Tạo lại rate calendar
    for (const priceSetting of priceSettings) {
      try {
        await this.syncRateCalendar(priceSetting);
        syncedCount++;
      } catch (error) {
        errors.push({
          id: priceSetting.id,
          error: error instanceof Error ? error.message : 'Unknown error',
        });
      }
    }

    return {
      success: errors.length === 0,
      message: `Synced ${syncedCount}/${priceSettings.length} active price settings to rate calendar`,
      total: priceSettings.length,
      synced: syncedCount,
      errors: errors.length > 0 ? errors : undefined,
    };
  }```

